1	//! Concurrent scaling benchmarks.
2	//!
3	//! Measures how the system scales under increasing concurrency:
4	//! - Distillation throughput with N parallel distill operations
5	//! - Immune scanning throughput with M parallel scans
6	//!
7	//! Uses `tokio::runtime::Runtime::block_on` to parallelize work within
8	//! synchronous Criterion benchmark iterations.
9	
10	use std::fmt::Write;  // write! on String
11	use ans_distill::Distiller;
12	use ans_immune::detector::InjectionDetector;
13	use criterion::{black_box, criterion_group, criterion_main, Criterion, Throughput};
14	use serde_json::json;
15	use std::sync::Arc;
16	use tokio::runtime::Runtime;
