18	fn build_dom(leaf_count: usize) -> serde_json::Value {
19	    let leaves: Vec<_> = (0..leaf_count)
20	        .map(|i| {
21	            json!({
22	                "nodeType": 1,
23	                "nodeName": "span",
24	                "attributes": [{"name": "class", "value": format!("item-{}", i)}],
25	                "children": [{
26	                    "nodeType": 3,
27	                    "nodeValue": format!("Leaf {}", i)
28	                }]
29	            })
30	        })
31	        .collect();
32	
33	    json!({
34	        "root": {
35	            "nodeType": 9, "nodeName": "#document",
36	            "children": [{
37	                "nodeType": 1, "nodeName": "HTML",
38	                "children": [{
39	                    "nodeType": 1, "nodeName": "HEAD", "children": []
40	                }, {
41	                    "nodeType": 1, "nodeName": "BODY",
42	                    "children": [{
43	                        "nodeType": 1, "nodeName": "div",
44	                        "children": leaves
45	                    }]
46	                }]
47	            }]
48	        }
49	    })
50	}
51	
52	// ── Concurrent distillation ──────────────────────────────────
53	
54	#[allow(clippy::unwrap_used)]
55	fn bench_concurrent_distill(c: &mut Criterion) {
56	    let rt = Runtime::new().unwrap();
57	    let dom = Arc::new(build_dom(500));
58	
59	    for concurrency in [1, 4, 8, 16] {
60	        let dom = Arc::clone(&dom);
61	        let rt_handle = rt.handle().clone();
62	
63	        let mut group = c.benchmark_group("concurrent_distill");
64	        group.throughput(Throughput::Elements(500 * concurrency as u64));
65	        group.bench_function(format!("{concurrency}_tasks"), |b| {
66	            b.iter(|| {
67	                rt_handle.block_on(async {
