72	                            Distiller.process(
73	                                black_box(&dom),
74	                                DistillMode::AllFields,
75	                                "https://example.com",
76	                                "Concurrent Page",
77	                            )
78	                        }));
79	                    }
80	                    for h in handles {
81	                        let _ = h.await;
82	                    }
83	                });
84	            });
85	        });
86	        group.finish();
87	    }
88	}
89	
90	// ── Concurrent immune scanning ───────────────────────────────
91	
92	#[allow(clippy::unwrap_used)]
93	fn bench_concurrent_immune(c: &mut Criterion) {
94	    let rt = Runtime::new().unwrap();
95	    let mut html = String::with_capacity(50_000);
96	    html.push_str("<html><body>");
97	    for i in 0..1000 {
98	        let _ = write!(html, "<div id='d{i}'><input id='f{i}' placeholder='Field {i}' /></div>");
99	    }
100	    html.push_str("</body></html>");
