48	
49	// ── Distillation benchmarks ──────────────────────────────────
50	
51	fn bench_distill_small(c: &mut Criterion) {
52	    let dom = build_dom(100);
53	    let distiller = Distiller;
54	    let mut group = c.benchmark_group("distill");
55	    group.throughput(Throughput::Elements(100));
