222	/// Locate a Chromium/Chrome executable on the system.
223	fn find_chromium() -> Result<PathBuf, LaunchError> {
224	    let exe_names: &[&str] = if cfg!(target_os = "windows") {
225	        &["chromium.exe", "chrome.exe"]
226	    } else {
227	        &["chromium", "chromium-browser", "chrome", "google-chrome"]
228	    };
229	
230	    // 1. Search PATH
231	    if let Ok(path_var) = std::env::var("PATH") {
232	        for dir in std::env::split_paths(&path_var) {
233	            for name in exe_names {
234	                let candidate = dir.join(name);
235	                if candidate.is_file() {
236	                    tracing::debug!(path = %candidate.display(), "Found Chromium on PATH");
237	                    return Ok(candidate);
238	                }
239	            }
240	        }
241	    }
242	
243	    // 2. macOS: check Application bundles
244	    #[cfg(target_os = "macos")]
245	    {
246	        let mac_paths = [
247	            "/Applications/Chromium.app/Contents/MacOS/Chromium",
248	            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
249	        ];
250	        for p in &mac_paths {
251	            let pb = PathBuf::from(p);
252	            if pb.is_file() {
253	                return Ok(pb);
254	            }
255	        }
256	    }
257	
258	    // 3. Windows: check common install directories
259	    #[cfg(target_os = "windows")]
260	    {
261	        let locals = [
262	            std::env::var("LOCALAPPDATA"),
263	            std::env::var("ProgramFiles"),
264	            std::env::var("ProgramFiles(x86)"),
265	        ];
266	        for local_var in locals.iter().flatten() {
267	            let candidates = [
268	                PathBuf::from(local_var).join("Chromium\\Application\\chrome.exe"),
269	                PathBuf::from(local_var).join("Google\\Chrome\\Application\\chrome.exe"),
270	            ];
271	            for p in &candidates {
272	                if p.is_file() {
273	                    tracing::debug!(path = %p.display(), "Found Chromium via install path");
274	                    return Ok(p.clone());
275	                }
276	            }
277	        }
278	    }
279	
280	    Err(LaunchError::ChromiumNotFound)
281	}
282	
283	// ── Error type ───────────────────────────────────────────────────────
284	
285	#[derive(Debug, thiserror::Error)]
286	pub enum LaunchError {
287	    #[error("chromium executable not found on PATH or common install locations")]
288	    ChromiumNotFound,
289	
290	    #[error("failed to allocate ephemeral port: {0}")]
291	    PortAllocation(#[from] std::io::Error),
292	
293	    #[error("failed to spawn {exe}: {source}")]
294	    SpawnFailed {
295	        exe: PathBuf,
296	        #[source]
297	        source: std::io::Error,
298	    },
299	
300	    #[error("webSocketDebuggerUrl not found in /json/version response")]
301	    DebugUrlNotFound,
302	
303	    #[error("HTTP request to {url} failed: {source}")]
304	    HttpConnectionFailed {
305	        url: String,
306	        #[source]
307	        source: reqwest::Error,
308	    },
309	
310	    #[error("HTTP response parse error: {0}")]
311	    HttpParse(#[from] reqwest::Error),
312	}
