1	//! CDP WebSocket client implementing [`ans_core::BrowserBackend`].
2	//!
3	//! Architecture:
4	//! ```text
5	//! CdpBackend
6	//!   ├── ChromiumProcess (owns child process)
7	//!   └── CdpConnection
8	//!         ├── write_tx: mpsc::Sender<String>  (outgoing commands)
9	//!         ├── pending: Arc<Mutex<HashMap<id, oneshot::Sender>>>
10	//!         └── reader task (spawned, reads WS messages)
11	//! ```
12	
13	use std::collections::HashMap;
14	use std::sync::Arc;
15	use std::time::Duration;
16	
17	use ans_core::backend::{BrowserError, ImageFormat, PageState};
18	use ans_core::distill::{DistillMode, DistilledPage};
19	use ans_core::session::ActionOutcome;
20	use async_trait::async_trait;
21	use futures_util::{SinkExt, StreamExt};
22	use tokio::sync::{mpsc, oneshot, Mutex};
