29	// ── CdpConnection ────────────────────────────────────────────────────
30	
31	type PendingMap = Arc<Mutex<HashMap<i64, oneshot::Sender<Result<serde_json::Value, CdpError>>>>>;
32	
33	struct CdpConnection {
34	    write_tx: mpsc::Sender<String>,
35	    pending: PendingMap,
36	}
37	
38	impl CdpConnection {
39	    /// Establish a WebSocket connection and spawn the reader task.
40	    async fn connect(debug_url: &str) -> Result<Self, BrowserError> {
41	        let (ws, _) = tokio_tungstenite::connect_async(debug_url)
42	            .await
43	            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;
44	
45	        let (mut write, read) = ws.split();
46	        let (write_tx, mut write_rx) = mpsc::channel::<String>(256);
47	        let pending: PendingMap = Arc::new(Mutex::new(HashMap::new()));
48	
49	        // Writer task: pumps messages from the mpsc channel to the WebSocket
50	        let writer_pending = pending.clone();
51	        tokio::spawn(async move {
52	            while let Some(msg) = write_rx.recv().await {
53	                if let Err(e) = write.send(Message::Text(msg)).await {
54	                    let _ = writer_pending.lock().await;
55	                    tracing::error!(?e, "CDP write failed");
56	                    break;
57	                }
58	            }
59	        });
60	
61	        // Reader task: reads WebSocket messages, dispatches responses to pending
62	        // commands, and forwards events to the broadcast channel
63	        let reader_pending = pending.clone();
64	        tokio::spawn(async move {
65	            let mut read = read;
66	            while let Some(msg) = read.next().await {
67	                match msg {
68	                    Ok(Message::Text(text)) => {
69	                        let text_str = text.clone();
70	                        if let Some(cdp_msg) = command::parse_message(&text_str) {
71	                            match cdp_msg {
72	                                CdpMessage::Response(resp) => {
73	                                    let id = resp.id;
74	                                    let result = resp.into_result();
75	                                    let mut map = reader_pending.lock().await;
76	                                    if let Some(tx) = map.remove(&id) {
77	                                        let _ = tx.send(result);
78	                                    }
79	                                }
80	                                CdpMessage::Event(event) => {
81	                                    tracing::trace!(
82	                                        method = %event.method,
83	                                        "CDP event"
84	                                    );
85	                                }
86	                            }
87	                        }
88	                    }
89	                    Err(e) => {
90	                        tracing::error!(?e, "CDP WebSocket read error");
91	                        break;
92	                    }
93	                    _ => {}
94	                }
95	            }
96	            tracing::debug!("CDP reader task exiting");
97	        });
98	
99	        Ok(Self { write_tx, pending })
100	    }
101	
102	    /// Send a CDP command and await its response with a timeout.
103	    async fn send_command(
104	        &self,
105	        cmd: CdpCommand,
106	        timeout: Duration,
107	    ) -> Result<serde_json::Value, BrowserError> {
108	        let (tx, rx) = oneshot::channel();
109	        let id = cmd.id;
110	
111	        self.pending.lock().await.insert(id, tx);
112	        let json = cmd.to_json();
113	
114	        self.write_tx
115	            .send(json)
116	            .await
117	            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;
118	
119	        tokio::time::timeout(timeout, rx)
120	            .await
121	            .map_err(|_| BrowserError::NavigationTimeout(timeout))?
122	            .map_err(|_| BrowserError::ConnectionLost("sender dropped".into()))?
123	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))
124	    }
125	}
