127	// ── CdpBackend ───────────────────────────────────────────────────────
128	
129	/// CDP-backed browser implementation.
130	///
131	/// Owns the Chromium child process and the WebSocket connection.
132	pub struct CdpBackend {
133	    // Held for RAII cleanup: Chromium is killed on Drop.
134	    _process: ChromiumProcess,
135	    connection: CdpConnection,
136	    // Current page state, updated after navigations.
137	    current_url: Mutex<String>,
138	}
