140	impl CdpBackend {
141	    /// Launch a new Chromium instance and establish a CDP connection.
142	    pub async fn launch() -> Result<Self, BrowserError> {
143	        let process = ChromiumProcess::launch()
144	            .await
145	            .map_err(|e| BrowserError::Internal(e.into()))?;
146	
147	        // Connect to the page-level WebSocket URL (not browser-level).
148	        // Page.*, DOM.*, and Runtime.* commands require a page target connection.
149	        let page_url = process.page_url().to_string();
150	        let connection = CdpConnection::connect(&page_url).await?;
151	
152	        // Enable domains we need
153	        connection
154	            .send_command(command::page_enable(), Duration::from_secs(10))
155	            .await?;
156	        connection
157	            .send_command(command::dom_enable(), Duration::from_secs(10))
158	            .await?;
159	        connection
160	            .send_command(command::runtime_enable(), Duration::from_secs(10))
161	            .await?;
162	
163	        tracing::info!("CDP backend ready");
164	
165	        Ok(Self {
166	            _process: process,
167	            connection,
168	            current_url: Mutex::new(String::new()),
169	        })
170	    }
171	
172	    /// Send a command and drop the response (fire-and-forget).
173	    async fn send_ignore(&self, cmd: CdpCommand) {
174	        let json = cmd.to_json();
175	        let _ = self.connection.write_tx.send(json).await;
176	    }
177	}
