191	        let frame_tree = self
192	            .connection
193	            .send_command(command::page_get_frame_tree(), timeout)
194	            .await?;
195	        let tree = command::parse_frame_tree(&frame_tree);
196	        let info = command::parse_page_info(&tree);
197	
198	        // Try to get title via JS
199	        let title = self
200	            .connection
201	            .send_command(
202	                command::runtime_evaluate("document.title"),
203	                Duration::from_secs(5),
204	            )
205	            .await
206	            .ok()
207	            .and_then(|v| v.as_str().map(String::from))
208	            .unwrap_or_else(|| info.title.clone());
209	
210	        let dom_nodes = self
