302	    async fn click(&self, selector: &str) -> Result<ActionOutcome, BrowserError> {
303	        let start = std::time::Instant::now();
304	
305	        // 1. Get document root
306	        let doc_result = self
307	            .connection
308	            .send_command(command::dom_get_document(0), Duration::from_secs(5))
309	            .await?;
310	        let root_id = command::parse_dom_node_id(&doc_result)
311	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
312	
313	        // 2. Query selector
314	        let qs_result = self
315	            .connection
316	            .send_command(
317	                command::dom_query_selector(root_id, selector),
318	                Duration::from_secs(5),
319	            )
320	            .await
321	            .map_err(|e| {
322	                if matches!(e, BrowserError::CdpProtocol(_)) {
323	                    BrowserError::SelectorNotFound(selector.to_string())
324	                } else {
325	                    e
326	                }
327	            })?;
328	
329	        let node_id = command::parse_query_selector_result(&qs_result)
330	            .map_err(|_| BrowserError::SelectorNotFound(selector.to_string()))?;
331	
332	        // 3. Get box model for coordinates
333	        let box_result = self
334	            .connection
335	            .send_command(command::dom_get_box_model(node_id), Duration::from_secs(5))
336	            .await?;
337	        let box_model = command::parse_box_model(&box_result)
338	            .map_err(|_| BrowserError::NotInteractable(selector.to_string()))?;
339	
340	        let center_x = box_model.x + box_model.width / 2.0;
341	        let center_y = box_model.y + box_model.height / 2.0;
342	
343	        // 4. Scroll element into view
344	        let _ = self
345	            .connection
346	            .send_command(
347	                command::dom_scroll_into_view(node_id),
348	                Duration::from_secs(5),
349	            )
350	            .await;
351	
352	        // Brief delay for scroll animation
353	        tokio::time::sleep(Duration::from_millis(100)).await;
354	
355	        // 5. Dispatch mouse events
356	        self.send_ignore(command::input_dispatch_mouse_event(
357	            "mousePressed",
358	            center_x,
359	            center_y,
360	            "left",
361	        ))
362	        .await;
363	        tokio::time::sleep(Duration::from_millis(50)).await;
364	        self.send_ignore(command::input_dispatch_mouse_event(
365	            "mouseReleased",
366	            center_x,
367	            center_y,
368	            "left",
369	        ))
370	        .await;
371	
372	        let elapsed = start.elapsed();
373	
374	        Ok(ActionOutcome {
375	            success: true,
376	            error_message: None,
377	            execution_time_ms: elapsed.as_millis() as u64,
378	            page_url_after: Some(self.current_url.lock().await.clone()),
379	            dom_changed: true,
380	        })
381	    }
