403	    async fn select_option(
404	        &self,
405	        selector: &str,
406	        value: &str,
407	    ) -> Result<ActionOutcome, BrowserError> {
408	        let start = std::time::Instant::now();
409	
410	        // Use JS to set the select value and dispatch a change event
411	        let script = format!(
412	            r"
413	            (function() {{
414	                var el = document.querySelector('{}');
415	                if (!el) return 'selector not found';
416	                el.value = '{}';
417	                el.dispatchEvent(new Event('change', {{ bubbles: true }}));
418	                return 'ok';
419	            }})()
