484	    async fn wait_for_load(&self, timeout: Duration) -> Result<PageState, BrowserError> {
485	        // Poll document.readyState until complete or timeout
486	        let start = std::time::Instant::now();
487	        loop {
488	            let cmd = command::runtime_evaluate("document.readyState");
489	            if let Ok(result) = self
490	                .connection
491	                .send_command(cmd, Duration::from_secs(3))
492	                .await
493	            {
494	                if let Ok(val) = command::parse_evaluate_result(&result) {
495	                    if val.as_str() == Some("complete") {
