538	/// Escape a string for safe embedding in a JavaScript string literal.
539	fn escape_js_string(s: &str) -> String {
540	    s.replace('\\', "\\\\")
541	        .replace('\'', "\\'")
542	        .replace('\n', "\\n")
543	        .replace('\r', "\\r")
