fn patch_navigator_webdriver() -> String {
    r#"
(function() {
    if (navigator.webdriver === undefined) return;
    Object.defineProperty(Object.getPrototypeOf(navigator), 'webdriver', {
        get: function() { return false; },
        set: function() {},
        configurable: true,
        enumerable: true
    });
})();
"#
    .to_string()
}

