    fn test_linux_profile() {
        let p = FingerprintProfile::linux_chrome();
        assert_eq!(p.platform, "Linux x86_64");
    }

    #[test]
    fn test_random_variation_changes_screen() {
        let base = FingerprintProfile::windows_chrome();
        let mut saw_different = false;
        for _ in 0..20 {
