/// Locate a Chromium/Chrome executable on the system.
fn find_chromium() -> Result<PathBuf, LaunchError> {
    let exe_names: &[&str] = if cfg!(target_os = "windows") {
        &["chromium.exe", "chrome.exe"]
    } else {
        &["chromium", "chromium-browser", "chrome", "google-chrome"]
    };

    // 1. Search PATH
    if let Ok(path_var) = std::env::var("PATH") {
        for dir in std::env::split_paths(&path_var) {
            for name in exe_names {
                let candidate = dir.join(name);
                if candidate.is_file() {
                    tracing::debug!(path = %candidate.display(), "Found Chromium on PATH");
                    return Ok(candidate);
                }
            }
        }
    }

    // 2. macOS: check Application bundles
    #[cfg(target_os = "macos")]
    {
        let mac_paths = [
            "/Applications/Chromium.app/Contents/MacOS/Chromium",
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        ];
        for p in &mac_paths {
            let pb = PathBuf::from(p);
            if pb.is_file() {
                return Ok(pb);
            }
        }
    }

    // 3. Windows: check common install directories
    #[cfg(target_os = "windows")]
    {
        let locals = [
            std::env::var("LOCALAPPDATA"),
            std::env::var("ProgramFiles"),
            std::env::var("ProgramFiles(x86)"),
        ];
        for local_var in locals.iter().flatten() {
            let candidates = [
                PathBuf::from(local_var).join("Chromium\\Application\\chrome.exe"),
                PathBuf::from(local_var).join("Google\\Chrome\\Application\\chrome.exe"),
            ];
            for p in &candidates {
                if p.is_file() {
                    tracing::debug!(path = %p.display(), "Found Chromium via install path");
                    return Ok(p.clone());
                }
            }
        }
    }

    Err(LaunchError::ChromiumNotFound)
}

// ── Error type ───────────────────────────────────────────────────────

#[derive(Debug, thiserror::Error)]
pub enum LaunchError {
    #[error("chromium executable not found on PATH or common install locations")]
    ChromiumNotFound,

    #[error("failed to allocate ephemeral port: {0}")]
    PortAllocation(#[from] std::io::Error),

    #[error("failed to spawn {exe}: {source}")]
    SpawnFailed {
        exe: PathBuf,
        #[source]
        source: std::io::Error,
    },

    #[error("webSocketDebuggerUrl not found in /json/version response")]
    DebugUrlNotFound,

    #[error("HTTP request to {url} failed: {source}")]
    HttpConnectionFailed {
        url: String,
        #[source]
        source: reqwest::Error,
    },

    #[error("HTTP response parse error: {0}")]
    HttpParse(#[from] reqwest::Error),
}
