//! Session manager for goal-scoped browser sessions.
//!
//! Each session wraps a [`CdpBackend`] (Chromium instance) and is
//! identified by a UUID. Sessions are organized by goal — not by tab —
//! and share the same goal state store.

use std::collections::HashMap;
use std::sync::Arc;
use std::time::Duration;

use ans_cdp::CdpBackend;
use ans_core::backend::{BrowserBackend, BrowserError, ImageFormat, PageState};
use ans_core::distill::{DistillMode, DistilledPage};
use ans_core::session::{Action, ActionOutcome, SessionStatus};
use tokio::sync::RwLock;
use tracing;
use uuid::Uuid;

/// Handle to an active browser session.
pub struct SessionHandle {
    pub session_id: Uuid,
    pub goal_id: Uuid,
    pub backend: CdpBackend,
    pub current_url: String,
    pub status: SessionStatus,
}

/// Thread-safe session registry.
///
/// Cloning shares the underlying `Arc<RwLock<>>` — all references
/// see the same sessions.
#[derive(Clone)]
pub struct SessionManager {
    sessions: Arc<RwLock<HashMap<Uuid, SessionHandle>>>,
}

impl Default for SessionManager {
    fn default() -> Self {
        Self::new()
    }
}

impl SessionManager {
    #[must_use] 
    pub fn new() -> Self {
        Self {
            sessions: Arc::new(RwLock::new(HashMap::new())),
        }
    }

    /// Create a new session by launching a Chromium instance.
    /// If `start_url` is provided, navigate to it immediately.
    pub async fn create(
        &self,
        goal_id: Uuid,
        start_url: Option<String>,
    ) -> Result<Uuid, BrowserError> {
        let session_id = Uuid::new_v4();
        tracing::info!(%session_id, %goal_id, "Creating session");

        let backend = CdpBackend::launch().await?;

        if let Some(url) = &start_url {
            let _ = backend
                .navigate(url, Duration::from_secs(30))
                .await
                .map(|state| {
                    tracing::info!(url = %state.url, "Session started at URL");
                });
        }

        let handle = SessionHandle {
            session_id,
            goal_id,
            backend,
            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
            status: SessionStatus::Idle,
        };

        self.sessions.write().await.insert(session_id, handle);

        Ok(session_id)
    }

    /// Close a session and kill its Chromium process.
    pub async fn close(&self, session_id: Uuid) -> Result<(), BrowserError> {
        tracing::info!(%session_id, "Closing session");
        let handle = self.sessions.write().await.remove(&session_id);
        if let Some(handle) = handle {
            handle.backend.close().await?;
        }
        Ok(())
    }

    /// Close all active sessions.
    pub async fn close_all(&self) {
        let ids: Vec<Uuid> = self.sessions.read().await.keys().copied().collect();
        for id in ids {
            let _ = self.close(id).await;
        }
        tracing::info!("All sessions closed");
    }

    /// Execute an action on a session.
    pub async fn execute_action(
        &self,
        session_id: Uuid,
        action: &Action,
    ) -> Result<ActionOutcome, BrowserError> {
        let sessions = self.sessions.read().await;
        let handle = sessions
            .get(&session_id)
            .ok_or(BrowserError::BrowserClosed)?;

        let outcome = match action.action_type {
            ans_core::session::ActionType::Click => {
                let selector = action
                    .selector
                    .as_deref()
                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
                handle.backend.click(selector).await?
            }
            ans_core::session::ActionType::Type => {
                let selector = action
                    .selector
                    .as_deref()
                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
                let text = action.value.as_deref().unwrap_or("");
                handle.backend.type_text(selector, text).await?
            }
            ans_core::session::ActionType::Scroll => {
                let pixels = action.value.as_deref().and_then(|v| v.parse().ok());
                let selector = action.selector.as_deref();
                handle.backend.scroll(pixels, selector).await?
            }
            ans_core::session::ActionType::Select => {
                let selector = action
                    .selector
                    .as_deref()
                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
                let value = action.value.as_deref().unwrap_or("");
                handle.backend.select_option(selector, value).await?
            }
            ans_core::session::ActionType::Navigate => {
                let url = action
                    .value
                    .as_deref()
                    .ok_or_else(|| BrowserError::CdpProtocol("missing URL".into()))?;
                let state = handle
                    .backend
                    .navigate(url, Duration::from_secs(30))
                    .await?;
                ActionOutcome {
                    success: true,
                    error_message: None,
                    execution_time_ms: 0,
                    page_url_after: Some(state.url),
                    dom_changed: false,
                }
            }
            ans_core::session::ActionType::Wait => {
                let ms = action
                    .value
                    .as_deref()
                    .and_then(|v| v.parse().ok())
                    .unwrap_or(1000u64);
                tokio::time::sleep(Duration::from_millis(ms)).await;
                ActionOutcome {
                    success: true,
                    error_message: None,
                    execution_time_ms: ms,
                    page_url_after: None,
                    dom_changed: false,
                }
            }
            ans_core::session::ActionType::Submit => {
                // Submit is typically handled as a click on a submit button
                // or pressing Enter. Evaluate a JS submit on the form.
                let selector = action.selector.as_deref().unwrap_or("form");
                let result = handle
                    .backend
                    .execute_script(&format!(
                        "(function(){{var f=document.querySelector('{}');if(f){{f.submit();return'ok'}}return'not found'}})()",
                        escape_for_js(selector)
                    ))
                    .await?;
                ActionOutcome {
                    success: result.contains("ok"),
                    error_message: if result.contains("ok") {
                        None
                    } else {
                        Some("form not found".into())
                    },
                    execution_time_ms: 0,
                    page_url_after: None,
                    dom_changed: true,
                }
            }
            ans_core::session::ActionType::Screenshot => {
                let _bytes = handle
                    .backend
                    .capture_screenshot(ans_core::backend::ImageFormat::Png, false)
                    .await?;
                ActionOutcome {
                    success: true,
                    error_message: None,
                    execution_time_ms: 0,
                    page_url_after: None,
                    dom_changed: false,
                }
            }
        };

        Ok(outcome)
    }

    /// Navigate a session to a URL.
    pub async fn navigate(&self, session_id: Uuid, url: &str) -> Result<PageState, BrowserError> {
        let sessions = self.sessions.read().await;
        let handle = sessions
            .get(&session_id)
            .ok_or(BrowserError::BrowserClosed)?;

        handle.backend.navigate(url, Duration::from_secs(30)).await
    }

    /// Distill the DOM in a session's current page.
    pub async fn get_distilled_dom(
        &self,
        session_id: Uuid,
        mode: DistillMode,
    ) -> Result<DistilledPage, BrowserError> {
        let sessions = self.sessions.read().await;
        let handle = sessions
            .get(&session_id)
            .ok_or(BrowserError::BrowserClosed)?;
        handle.backend.get_distilled_dom(mode).await
    }

    /// Capture a screenshot from a session's current page.
    pub async fn capture_screenshot(
        &self,
        session_id: Uuid,
        format: ImageFormat,
        full_page: bool,
    ) -> Result<Vec<u8>, BrowserError> {
        let sessions = self.sessions.read().await;
        let handle = sessions
            .get(&session_id)
            .ok_or(BrowserError::BrowserClosed)?;
        handle.backend.capture_screenshot(format, full_page).await
    }

    /// Get the number of active sessions.
    #[must_use] 
    pub fn session_count(&self) -> usize {
        self.sessions.try_read().map_or(0, |g| g.len())
    }

    /// Get the current URL for a session without fetching DOM.
    pub async fn get_url(&self, session_id: Uuid) -> Option<String> {
        let sessions = self.sessions.read().await;
        sessions.get(&session_id).map(|h| h.current_url.clone())
    }
}

fn escape_for_js(s: &str) -> String {
    s.replace('\\', "\\\\")
        .replace('\'', "\\'")
        .replace('\n', "\\n")
}

//! Human-like input behavior for mouse and keyboard.
//!
//! Generates bezier curve paths for mouse movement and variable
//! typing delays based on character frequency (common letters = faster).

use std::time::Duration;

/// Generate a bezier-based mouse path from (x1,y1) to (x2,y2).
///
/// Returns a vector of intermediate points plus the destination.
/// Each step represents ~8ms of movement for realistic cursor
/// velocity (~500px/s average).
#[must_use]
pub fn bezier_path(
    from: (f64, f64),
    to: (f64, f64),
) -> Vec<(f64, f64)> {
    let dx = to.0 - from.0;
    let dy = to.1 - from.1;
    let dist = (dx * dx + dy * dy).sqrt();

    if dist < 5.0 {
        return vec![to];
    }

    // Control points: random offset perpendicular to the line
    let angle = dy.atan2(dx);
    let perp = angle + std::f64::consts::FRAC_PI_2;

    // Random offset magnitude proportional to distance
    let offset = dist * 0.15 * fast_random();
    let wobble_x = offset * perp.cos();
    let wobble_y = offset * perp.sin();

    let cp1 = (from.0 + dx * 0.33 + wobble_x, from.1 + dy * 0.33 + wobble_y);
    let cp2 = (from.0 + dx * 0.66 - wobble_x, from.1 + dy * 0.66 - wobble_y);

    // Number of steps based on distance (realistic: ~500px/s, ~8ms/step)
    let steps = (dist / 4.0) as usize;
    let steps = steps.clamp(8, 120);

    let mut path = Vec::with_capacity(steps + 1);
    for i in 0..steps {
        let t = (i + 1) as f64 / steps as f64;
        // Cubic bezier: B(t) = (1-t)^3*P0 + 3(1-t)^2*t*P1 + 3(1-t)*t^2*P2 + t^3*P3
        let mt = 1.0 - t;
        let x = mt * mt * mt * from.0
            + 3.0 * mt * mt * t * cp1.0
            + 3.0 * mt * t * t * cp2.0
            + t * t * t * to.0;
        let y = mt * mt * mt * from.1
            + 3.0 * mt * mt * t * cp1.1
            + 3.0 * mt * t * t * cp2.1
            + t * t * t * to.1;

        // Add micro-jitter: human hand tremor (sub-pixel)
        let jitter_x = (fast_random() - 0.5) * 0.8;
        let jitter_y = (fast_random() - 0.5) * 0.8;

        path.push((x + jitter_x, y + jitter_y));
    }

    path
}

/// Human-like typing delay for a given character.
///
/// Common letters (e, t, a, o, i, n, s, h, r) get 40-80ms.
/// Rare letters get 60-120ms.
/// Space and punctuation get 30-60ms.
/// Uppercase adds shift-key overhead.
#[must_use]
pub fn typing_delay(c: char, _total_chars_typed: usize) -> Duration {
    let base_ms = match c {
        ' ' | '.' | ',' | ';' => fast_random_range(30.0, 60.0),
        'e' | 't' | 'a' | 'o' | 'i' | 'n' | 's' | 'h' | 'r' => {
            fast_random_range(40.0, 80.0)
        }
        _ if c.is_uppercase() => fast_random_range(70.0, 140.0), // shift overhead
        _ => fast_random_range(60.0, 120.0),
    };
    Duration::from_millis(base_ms as u64)
}

/// Random delay between actions (think time).
#[must_use]
pub fn think_delay() -> Duration {
    Duration::from_millis(fast_random_range(200.0, 800.0) as u64)
}

/// Random delay after a click (reaction time).
#[must_use]
pub fn click_linger() -> Duration {
    Duration::from_millis(fast_random_range(150.0, 400.0) as u64)
}

/// Sub-pixel position jitter for click coordinates.
/// Prevents clicking the exact center of elements every time.
#[must_use]
pub fn position_jitter() -> f64 {
    (fast_random() - 0.5) * 4.0
}

// ── Internal fast RNG (no crypto needed for humanization) ──────────

fn fast_random() -> f64 {
    // Simple xorshift — fast, no allocation, good enough for jitter
    use std::cell::Cell;
    thread_local! {
        static STATE: Cell<u64> = Cell::new(0xDEAD_BEEF_CAFE_BABE);
    }
    STATE.with(|state| {
        let mut x = state.get();
        if x == 0 { x = 0xDEAD_BEEF_CAFE_BABE; }
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        state.set(x);
        (x as f64) / (u64::MAX as f64)
    })
}

fn fast_random_range(min: f64, max: f64) -> f64 {
    min + fast_random() * (max - min)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_bezier_short_path() {
        let path = bezier_path((100.0, 100.0), (105.0, 105.0));
        assert_eq!(path.len(), 1);
        assert_eq!(path[0], (105.0, 105.0));
    }

    #[test]
    fn test_bezier_long_path() {
        let path = bezier_path((0.0, 0.0), (500.0, 300.0));
        // Should have many intermediate points
        assert!(path.len() > 10);
        // Last point should be very close to destination
        let last = path.last().unwrap();
        assert!((last.0 - 500.0).abs() < 3.0);
        assert!((last.1 - 300.0).abs() < 3.0);
    }

    #[test]
    fn test_bezier_points_are_monotonic_ish() {
        let path = bezier_path((0.0, 0.0), (100.0, 100.0));
        // Path should generally progress toward destination
        for i in 1..path.len() {
            let prev = path[i - 1];
            let curr = path[i];
            let dist_before = (prev.0 * prev.0 + prev.1 * prev.1).sqrt();
            let dist_after = (curr.0 * curr.0 + curr.1 * curr.1).sqrt();
            // Points get further from origin (generally)
            assert!(
                dist_after > dist_before - 2.0,
                "point {i} ({curr:?}) moved backwards from {prev:?}"
            );
        }
    }

    #[test]
    fn test_typing_delay_reasonable() {
        for c in ['e', 'A', ' ', 'q'] {
            let delay = typing_delay(c, 0);
            assert!(delay.as_millis() >= 30, "delay for '{c}' too short");
            assert!(delay.as_millis() <= 150, "delay for '{c}' too long");
        }
    }

    #[test]
    fn test_think_delay_reasonable() {
        for _ in 0..10 {
            let d = think_delay();
            assert!(d.as_millis() >= 200);
            assert!(d.as_millis() <= 800);
        }
    }
}

//! CDP WebSocket client implementing [`ans_core::BrowserBackend`].
//!
//! Architecture:
//! ```text
//! CdpBackend
//!   ├── ChromiumProcess (owns child process)
//!   └── CdpConnection
//!         ├── write_tx: mpsc::Sender<String>  (outgoing commands)
//!         ├── pending: Arc<Mutex<HashMap<id, oneshot::Sender>>>
//!         └── reader task (spawned, reads WS messages)
//! ```

use std::collections::HashMap;
use std::sync::Arc;
use std::time::Duration;

use ans_core::backend::{BrowserError, ImageFormat, PageState};
use ans_core::distill::{DistillMode, DistilledPage};
use ans_core::session::ActionOutcome;
use ans_stealth::StealthConfig;
use async_trait::async_trait;
use futures_util::{SinkExt, StreamExt};
use tokio::sync::{mpsc, oneshot, Mutex};
use tokio_tungstenite::tungstenite::Message;
use tracing;

use crate::command::{self, CdpCommand, CdpError, CdpMessage};
use crate::process::ChromiumProcess;

// ── CdpConnection ────────────────────────────────────────────────────

type PendingMap = Arc<Mutex<HashMap<i64, oneshot::Sender<Result<serde_json::Value, CdpError>>>>>;

struct CdpConnection {
    write_tx: mpsc::Sender<String>,
    pending: PendingMap,
}

impl CdpConnection {
    /// Establish a WebSocket connection and spawn the reader task.
    async fn connect(debug_url: &str) -> Result<Self, BrowserError> {
        let (ws, _) = tokio_tungstenite::connect_async(debug_url)
            .await
            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;

        let (mut write, read) = ws.split();
        let (write_tx, mut write_rx) = mpsc::channel::<String>(256);
        let pending: PendingMap = Arc::new(Mutex::new(HashMap::new()));

        // Writer task: pumps messages from the mpsc channel to the WebSocket
        let writer_pending = pending.clone();
        tokio::spawn(async move {
            while let Some(msg) = write_rx.recv().await {
                if let Err(e) = write.send(Message::Text(msg)).await {
                    let _ = writer_pending.lock().await;
                    tracing::error!(?e, "CDP write failed");
                    break;
                }
            }
        });

        // Reader task: reads WebSocket messages, dispatches responses to pending
        // commands, and forwards events to the broadcast channel
        let reader_pending = pending.clone();
        tokio::spawn(async move {
            let mut read = read;
            while let Some(msg) = read.next().await {
                match msg {
                    Ok(Message::Text(text)) => {
                        let text_str = text.clone();
                        if let Some(cdp_msg) = command::parse_message(&text_str) {
                            match cdp_msg {
                                CdpMessage::Response(resp) => {
                                    let id = resp.id;
                                    let result = resp.into_result();
                                    let mut map = reader_pending.lock().await;
                                    if let Some(tx) = map.remove(&id) {
                                        let _ = tx.send(result);
                                    }
                                }
                                CdpMessage::Event(event) => {
                                    tracing::trace!(
                                        method = %event.method,
                                        "CDP event"
                                    );
                                }
                            }
                        }
                    }
                    Err(e) => {
                        tracing::error!(?e, "CDP WebSocket read error");
                        break;
                    }
                    _ => {}
                }
            }
            tracing::debug!("CDP reader task exiting");
        });

        Ok(Self { write_tx, pending })
    }

    /// Send a CDP command and await its response with a timeout.
    async fn send_command(
        &self,
        cmd: CdpCommand,
        timeout: Duration,
    ) -> Result<serde_json::Value, BrowserError> {
        let (tx, rx) = oneshot::channel();
        let id = cmd.id;

        self.pending.lock().await.insert(id, tx);
        let json = cmd.to_json();

        self.write_tx
            .send(json)
            .await
            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;

        tokio::time::timeout(timeout, rx)
            .await
            .map_err(|_| BrowserError::NavigationTimeout(timeout))?
            .map_err(|_| BrowserError::ConnectionLost("sender dropped".into()))?
            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))
    }
}

// ── CdpBackend ───────────────────────────────────────────────────────

/// CDP-backed browser implementation.
///
/// Owns the Chromium child process and the WebSocket connection.
pub struct CdpBackend {
    // Held for RAII cleanup: Chromium is killed on Drop.
    _process: ChromiumProcess,
    connection: CdpConnection,
    // Current page state, updated after navigations.
    current_url: Mutex<String>,
    /// Stealth configuration (anti-detection engine).
    /// Stored for use in mouse/keyboard humanization.
    stealth: Option<StealthConfig>,
}

impl CdpBackend {
    /// Launch a new Chromium instance and establish a CDP connection.
    ///
    /// When `stealth` is provided, anti-detection scripts are injected
    /// via `Page.addScriptToEvaluateOnNewDocument` before any page loads.
    pub async fn launch(stealth: Option<StealthConfig>) -> Result<Self, BrowserError> {
        let process = ChromiumProcess::launch(stealth.as_ref())
            .await
            .map_err(|e| BrowserError::Internal(e.into()))?;

        // Connect to the page-level WebSocket URL (not browser-level).
        // Page.*, DOM.*, and Runtime.* commands require a page target connection.
        let page_url = process.page_url().to_string();
        let connection = CdpConnection::connect(&page_url).await?;

        // Enable domains we need
        connection
            .send_command(command::page_enable(), Duration::from_secs(10))
            .await?;
        connection
            .send_command(command::dom_enable(), Duration::from_secs(10))
            .await?;
        connection
            .send_command(command::runtime_enable(), Duration::from_secs(10))
            .await?;

        // Inject anti-detection scripts before any page loads
        if let Some(ref config) = stealth {
            let scripts = config.init_scripts();
            if !scripts.is_empty() {
                tracing::info!(
                    count = scripts.len(),
                    level = ?config.level,
                    "Injecting stealth scripts"
                );
                for script in &scripts {
                    let cmd = command::page_add_script_to_evaluate_on_new_document(script);
                    if let Err(e) = connection
                        .send_command(cmd, Duration::from_secs(10))
                        .await
                    {
                        tracing::warn!(?e, "Failed to inject stealth script");
                    }
                }
            }
        }

        tracing::info!("CDP backend ready");

        Ok(Self {
            _process: process,
            connection,
            current_url: Mutex::new(String::new()),
            stealth,
        })
    }

    /// Send a command and drop the response (fire-and-forget).
    async fn send_ignore(&self, cmd: CdpCommand) {
        let json = cmd.to_json();
        let _ = self.connection.write_tx.send(json).await;
    }
}

#[async_trait]
impl ans_core::BrowserBackend for CdpBackend {
    async fn navigate(&self, url: &str, timeout: Duration) -> Result<PageState, BrowserError> {
        tracing::info!(%url, "Navigating");

        let cmd = command::page_navigate(url);
        let result = self.connection.send_command(cmd, timeout).await?;
        let _nav = command::parse_navigation_result(&result);

        // Wait briefly for the page to start loading, then get frame tree
        tokio::time::sleep(Duration::from_millis(500)).await;

        let frame_tree = self
            .connection
            .send_command(command::page_get_frame_tree(), timeout)
            .await?;
        let tree = command::parse_frame_tree(&frame_tree);
        let info = command::parse_page_info(&tree);

        // Try to get title via JS
        let title = self
            .connection
            .send_command(
                command::runtime_evaluate("document.title"),
                Duration::from_secs(5),
            )
            .await
            .ok()
            .and_then(|v| v.as_str().map(String::from))
            .unwrap_or_else(|| info.title.clone());

        let dom_nodes = self
            .connection
            .send_command(
                command::runtime_evaluate("document.querySelectorAll('*').length"),
                Duration::from_secs(5),
            )
            .await
            .ok()
            .and_then(|v| v.as_u64())
            .unwrap_or(0);

        let visible_text = self
            .connection
            .send_command(
                command::runtime_evaluate("document.body?.innerText?.slice(0, 2000) || ''"),
                Duration::from_secs(5),
            )
            .await
            .ok()
            .and_then(|v| {
                v.as_str().map(|s| {
                    s.lines()
                        .filter(|l| !l.trim().is_empty())
                        .map(String::from)
                        .take(50)
                        .collect::<Vec<_>>()
                })
            })
            .unwrap_or_default();

        *self.current_url.lock().await = info.url.clone();

        Ok(PageState {
            url: info.url,
            title,
            loaded: info.loaded,
            dom_node_count: dom_nodes,
            visible_text,
            timestamp: chrono::Utc::now(),
        })
    }

    async fn get_distilled_dom(&self, mode: DistillMode) -> Result<DistilledPage, BrowserError> {
        let doc_result = self
            .connection
            .send_command(command::dom_get_document(-1), Duration::from_secs(10))
            .await?;

        let title = self
            .connection
            .send_command(
                command::runtime_evaluate("document.title"),
                Duration::from_secs(3),
            )
            .await
            .ok()
            .and_then(|v| v.as_str().map(String::from))
            .unwrap_or_default();

        let url = self.current_url.lock().await.clone();
        let distiller = ans_distill::Distiller;
        Ok(distiller.process(&doc_result, mode, &url, &title))
    }

    async fn capture_screenshot(
        &self,
        format: ImageFormat,
        full_page: bool,
    ) -> Result<Vec<u8>, BrowserError> {
        let (fmt_str, quality) = match format {
            ImageFormat::Png => ("png", None),
            ImageFormat::Jpeg { quality } => ("jpeg", Some(quality)),
        };

        let mut params = serde_json::json!({ "format": fmt_str });
        if let Some(q) = quality {
            params["quality"] = serde_json::json!(q);
        }
        if full_page {
            params["captureBeyondViewport"] = serde_json::json!(true);
        }

        let cmd = CdpCommand::new("Page.captureScreenshot", params);
        let result = self
            .connection
            .send_command(cmd, Duration::from_secs(15))
            .await?;

        command::parse_screenshot_result(&result)
            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))
    }

    async fn click(&self, selector: &str) -> Result<ActionOutcome, BrowserError> {
        let start = std::time::Instant::now();

        // 1. Get document root
        let doc_result = self
            .connection
            .send_command(command::dom_get_document(0), Duration::from_secs(5))
            .await?;
        let root_id = command::parse_dom_node_id(&doc_result)
            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;

        // 2. Query selector
        let qs_result = self
            .connection
            .send_command(
                command::dom_query_selector(root_id, selector),
                Duration::from_secs(5),
            )
            .await
            .map_err(|e| {
                if matches!(e, BrowserError::CdpProtocol(_)) {
                    BrowserError::SelectorNotFound(selector.to_string())
                } else {
                    e
                }
            })?;

        let node_id = command::parse_query_selector_result(&qs_result)
            .map_err(|_| BrowserError::SelectorNotFound(selector.to_string()))?;

        // 3. Get box model for coordinates
        let box_result = self
            .connection
            .send_command(command::dom_get_box_model(node_id), Duration::from_secs(5))
            .await?;
        let box_model = command::parse_box_model(&box_result)
            .map_err(|_| BrowserError::NotInteractable(selector.to_string()))?;

        let mut center_x = box_model.x + box_model.width / 2.0;
        let mut center_y = box_model.y + box_model.height / 2.0;

        // Humanized: slight random offset from exact center + pre-click delay
        let humanize = self.stealth.as_ref().is_some_and(|s| s.humanize);
        if humanize {
            use ans_stealth::humanize;
            center_x += ans_stealth::humanize::position_jitter();
            center_y += ans_stealth::humanize::position_jitter();
            tokio::time::sleep(humanize::click_linger()).await;
        }

        // 4. Scroll element into view
        let _ = self
            .connection
            .send_command(
                command::dom_scroll_into_view(node_id),
                Duration::from_secs(5),
            )
            .await;

        // Brief delay for scroll animation
        tokio::time::sleep(Duration::from_millis(100)).await;

        // 5. Dispatch mouse events
        if humanize {
            // Seek to element with movement, then press/release
            self.send_ignore(command::input_dispatch_mouse_event(
                "mouseMoved",
                center_x,
                center_y,
                "none",
            ))
            .await;
            tokio::time::sleep(Duration::from_millis(20)).await;
        }

        self.send_ignore(command::input_dispatch_mouse_event(
            "mousePressed",
            center_x,
            center_y,
            "left",
        ))
        .await;
        tokio::time::sleep(Duration::from_millis(
            if humanize { 60 } else { 50 },
        ))
        .await;
        self.send_ignore(command::input_dispatch_mouse_event(
            "mouseReleased",
            center_x,
            center_y,
            "left",
        ))
        .await;

        let elapsed = start.elapsed();

        Ok(ActionOutcome {
            success: true,
            error_message: None,
            execution_time_ms: elapsed.as_millis() as u64,
            page_url_after: Some(self.current_url.lock().await.clone()),
            dom_changed: true,
        })
    }

    async fn type_text(&self, selector: &str, text: &str) -> Result<ActionOutcome, BrowserError> {
        let start = std::time::Instant::now();

        // Click the element first to focus it
        let _ = self.click(selector).await;

        // Humanized: type character-by-character with variable delays
        let humanize = self.stealth.as_ref().is_some_and(|s| s.humanize);
        if humanize {
            use ans_stealth::humanize;
            for (i, c) in text.chars().enumerate() {
                let ch = c.to_string();
                self.send_ignore(command::input_insert_text(&ch)).await;
                tokio::time::sleep(humanize::typing_delay(c, i)).await;
            }
        } else {
            self.send_ignore(command::input_insert_text(text)).await;
        }

        let elapsed = start.elapsed();

        Ok(ActionOutcome {
            success: true,
            error_message: None,
            execution_time_ms: elapsed.as_millis() as u64,
            page_url_after: Some(self.current_url.lock().await.clone()),
            dom_changed: true,
        })
    }

    async fn select_option(
        &self,
        selector: &str,
        value: &str,
    ) -> Result<ActionOutcome, BrowserError> {
        let start = std::time::Instant::now();

        // Use JS to set the select value and dispatch a change event
        let script = format!(
            r"
            (function() {{
                var el = document.querySelector('{}');
                if (!el) return 'selector not found';
                el.value = '{}';
                el.dispatchEvent(new Event('change', {{ bubbles: true }}));
                return 'ok';
            }})()
            ",
            escape_js_string(selector),
            escape_js_string(value),
        );

        let cmd = command::runtime_evaluate(&script);
        let result = self
            .connection
            .send_command(cmd, Duration::from_secs(5))
            .await?;
        let eval_result = command::parse_evaluate_result(&result)
            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;

        let success = eval_result.as_str() == Some("ok");
        let elapsed = start.elapsed();

        Ok(ActionOutcome {
            success,
            error_message: if success {
                None
            } else {
                eval_result.as_str().map(String::from)
            },
            execution_time_ms: elapsed.as_millis() as u64,
            page_url_after: Some(self.current_url.lock().await.clone()),
            dom_changed: true,
        })
    }

    async fn scroll(
        &self,
        pixels: Option<i32>,
        selector: Option<&str>,
    ) -> Result<ActionOutcome, BrowserError> {
        let start = std::time::Instant::now();

        let script = if let Some(sel) = selector {
            format!(
                "document.querySelector('{}')?.scrollIntoView({{ behavior: 'instant', block: 'center' }});",
                escape_js_string(sel)
            )
        } else if let Some(px) = pixels {
            format!("window.scrollBy(0, {px});")
        } else {
            "window.scrollBy(0, 300);".to_string()
        };

        let cmd = command::runtime_evaluate(&script);
        let _ = self
            .connection
            .send_command(cmd, Duration::from_secs(5))
            .await;

        let elapsed = start.elapsed();

        Ok(ActionOutcome {
            success: true,
            error_message: None,
            execution_time_ms: elapsed.as_millis() as u64,
            page_url_after: Some(self.current_url.lock().await.clone()),
            dom_changed: false,
        })
    }

    async fn wait_for_load(&self, timeout: Duration) -> Result<PageState, BrowserError> {
        // Poll document.readyState until complete or timeout
        let start = std::time::Instant::now();
        loop {
            let cmd = command::runtime_evaluate("document.readyState");
            if let Ok(result) = self
                .connection
                .send_command(cmd, Duration::from_secs(3))
                .await
            {
                if let Ok(val) = command::parse_evaluate_result(&result) {
                    if val.as_str() == Some("complete") {
                        break;
                    }
                }
            }

            if start.elapsed() > timeout {
                return Err(BrowserError::NavigationTimeout(timeout));
            }
            tokio::time::sleep(Duration::from_millis(200)).await;
        }

        let current_url = self.current_url.lock().await.clone();
        Ok(PageState {
            url: current_url,
            title: String::new(),
            loaded: true,
            dom_node_count: 0,
            visible_text: vec![],
            timestamp: chrono::Utc::now(),
        })
    }

    async fn execute_script(&self, script: &str) -> Result<String, BrowserError> {
        let cmd = command::runtime_evaluate(script);
        let result = self
            .connection
            .send_command(cmd, Duration::from_secs(10))
            .await?;
        let val = command::parse_evaluate_result(&result)
            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
        Ok(val.to_string())
    }

    async fn close(&self) -> Result<(), BrowserError> {
        tracing::info!("Closing CDP backend");
        // The Chromium process is killed on drop, but we also close
        // the WebSocket gracefully by dropping the sender.
        // Process cleanup happens in ChromiumProcess::drop.
        Ok(())
    }
}

/// Escape a string for safe embedding in a JavaScript string literal.
fn escape_js_string(s: &str) -> String {
    s.replace('\\', "\\\\")
        .replace('\'', "\\'")
        .replace('\n', "\\n")
        .replace('\r', "\\r")
}

//! Chromium process lifecycle management.
//!
//! Spawns headless Chromium with `--remote-debugging-port`, monitors
//! its health, and guarantees cleanup on drop.
//!
//! # Safety invariant
//!
//! When [`ChromiumProcess`] is dropped, the child process MUST be killed.
//! Zombie Chromium processes are a hard bug.

use std::net::TcpListener;
use std::path::PathBuf;
use std::time::Duration;

use ans_stealth::StealthConfig;
use tokio::process::{Child, Command};
use tracing;

/// Owns a running Chromium child process.
///
/// Created via [`ChromiumProcess::launch`]. On drop, the child is killed
/// and the temporary user-data directory is removed.
pub struct ChromiumProcess {
    child: Option<Child>,
    debug_port: u16,
    debug_url: String,
    /// WebSocket URL for the first page target (not the browser endpoint).
    page_url: String,
    user_data_dir: PathBuf,
}

impl ChromiumProcess {
    /// Launch a headless Chromium instance with remote debugging enabled.
    ///
    /// Finds the Chromium executable on PATH (or common install locations),
    /// allocates an ephemeral port, spawns the process, and waits for the
    /// debug WebSocket URL to become available.
    ///
    /// When `stealth` is provided, anti-detection flags are merged into
    /// the launch command.
    pub async fn launch(stealth: Option<&StealthConfig>) -> Result<Self, LaunchError> {
        let exe = find_chromium()?;
        let port = allocate_port()?;
        let user_data_dir =
            std::env::temp_dir().join(format!("ans-chromium-{}", uuid::Uuid::new_v4()));

        std::fs::create_dir_all(&user_data_dir)?;

        tracing::info!(
            exe = %exe.display(),
            port = port,
            user_data_dir = %user_data_dir.display(),
            stealth = stealth.is_some(),
            "Launching Chromium"
        );

        let mut cmd = Command::new(&exe);
        cmd.arg("--headless=new")
            .arg(format!("--remote-debugging-port={port}"))
            .arg(format!("--user-data-dir={}", user_data_dir.display()))
            .arg("--no-sandbox")
            .arg("--disable-gpu")
            .arg("--disable-dev-shm-usage")
            .arg("--disable-extensions")
            .arg("--disable-background-networking")
            .arg("--disable-sync")
            .arg("--disable-translate")
            .arg("--disable-default-apps")
            .arg("--hide-scrollbars")
            .arg("--metrics-recording-only")
            .arg("--mute-audio")
            .arg("--no-first-run")
            .arg("--window-size=1280,720")
            .arg("about:blank");

        // Merge stealth anti-detection flags
        if let Some(config) = stealth {
            for flag in config.chrome_flags() {
                cmd.arg(flag);
            }
        }

        let child = cmd
            .kill_on_drop(true)
            .spawn()
            .map_err(|e| LaunchError::SpawnFailed {
                exe: exe.clone(),
                source: e,
            })?;

        let debug_url = discover_debug_url(port).await?;
        let page_url = discover_page_url(port).await?;

        tracing::info!(%debug_url, %page_url, "Chromium ready");

        Ok(Self {
            child: Some(child),
            debug_port: port,
            debug_url,
            page_url,
            user_data_dir,
        })
    }

    /// The browser-level WebSocket URL (for Target.* commands only).
    #[must_use] 
    pub fn debug_url(&self) -> &str {
        &self.debug_url
    }

    /// The page-level WebSocket URL (for Page.*, DOM.*, Runtime.* commands).
    #[must_use] 
    pub fn page_url(&self) -> &str {
        &self.page_url
    }

    /// The TCP port Chromium is listening on for CDP connections.
    #[must_use] 
    pub const fn debug_port(&self) -> u16 {
        self.debug_port
    }
}

impl Drop for ChromiumProcess {
    fn drop(&mut self) {
        if let Some(mut child) = self.child.take() {
            tracing::debug!(pid = child.id(), "Killing Chromium child process");
            // kill_on_drop(true) handles this, but explicitly kill for clarity
            if let Err(e) = child.start_kill() {
                tracing::warn!(pid = child.id(), ?e, "Failed to kill Chromium process");
            }
        }
        if self.user_data_dir.exists() {
            if let Err(e) = std::fs::remove_dir_all(&self.user_data_dir) {
                tracing::warn!(dir = %self.user_data_dir.display(), ?e, "Failed to remove temp user-data dir");
            }
        }
    }
}

// ── Helpers ──────────────────────────────────────────────────────────

/// Allocate an ephemeral TCP port by binding to port 0 and reading the assigned port.
fn allocate_port() -> Result<u16, LaunchError> {
    let listener = TcpListener::bind("127.0.0.1:0")?;
    let port = listener.local_addr()?.port();
    drop(listener);
    Ok(port)
}

/// Discover the CDP WebSocket debug URL by polling Chromium's HTTP endpoint.
async fn discover_debug_url(port: u16) -> Result<String, LaunchError> {
    let url = format!("http://127.0.0.1:{port}/json/version");
    let client = reqwest::Client::new();

    // Chromium takes a moment to start. Retry with backoff.
    let mut attempts = 0;
    loop {
        match client
            .get(&url)
            .timeout(Duration::from_secs(5))
            .send()
            .await
        {
            Ok(resp) => {
                if resp.status().is_success() {
                    let json: serde_json::Value = resp.json().await?;
                    return json["webSocketDebuggerUrl"]
                        .as_str()
                        .map(String::from)
                        .ok_or(LaunchError::DebugUrlNotFound);
                }
            }
            Err(_) if attempts < 20 => {
                attempts += 1;
                tokio::time::sleep(Duration::from_millis(250)).await;
            }
            Err(e) => {
                return Err(LaunchError::HttpConnectionFailed { url, source: e });
            }
        }
    }
}

/// Discover the page-level CDP WebSocket URL by polling Chromium's `/json` endpoint.
///
/// The `/json/version` endpoint returns the browser-level WebSocket URL which only
/// supports `Browser.*` and `Target.*` domains. For `Page.*`, `DOM.*`, and `Runtime.*`
/// commands, we must connect to a specific page target's WebSocket URL.
async fn discover_page_url(port: u16) -> Result<String, LaunchError> {
    let url = format!("http://127.0.0.1:{port}/json");
    let client = reqwest::Client::new();

    let mut attempts = 0;
    loop {
        match client
            .get(&url)
            .timeout(Duration::from_secs(5))
            .send()
            .await
        {
            Ok(resp) => {
                if resp.status().is_success() {
                    let targets: Vec<serde_json::Value> = resp.json().await?;
                    // Find the first "page" type target (not "background_page", "worker", etc.)
                    for target in &targets {
                        let target_type = target["type"].as_str().unwrap_or("");
                        if target_type == "page" {
                            if let Some(page_url) =
                                target["webSocketDebuggerUrl"].as_str()
                            {
                                return Ok(page_url.to_string());
                            }
                        }
                    }
                    // If no explicit "page" type, fall back to the first target with a debug URL
                    for target in &targets {
                        if let Some(page_url) = target["webSocketDebuggerUrl"].as_str() {
                            return Ok(page_url.to_string());
                        }
                    }
                    return Err(LaunchError::DebugUrlNotFound);
                }
            }
            Err(_) if attempts < 20 => {
                attempts += 1;
                tokio::time::sleep(Duration::from_millis(250)).await;
            }
            Err(e) => {
                return Err(LaunchError::HttpConnectionFailed { url, source: e });
            }
        }
    }
}

/// Locate a Chromium/Chrome executable on the system.
fn find_chromium() -> Result<PathBuf, LaunchError> {
    let exe_names: &[&str] = if cfg!(target_os = "windows") {
        &["chromium.exe", "chrome.exe"]
    } else {
        &["chromium", "chromium-browser", "chrome", "google-chrome"]
    };

    // 1. Search PATH
    if let Ok(path_var) = std::env::var("PATH") {
        for dir in std::env::split_paths(&path_var) {
            for name in exe_names {
                let candidate = dir.join(name);
                if candidate.is_file() {
                    tracing::debug!(path = %candidate.display(), "Found Chromium on PATH");
                    return Ok(candidate);
                }
            }
        }
    }

    // 2. macOS: check Application bundles
    #[cfg(target_os = "macos")]
    {
        let mac_paths = [
            "/Applications/Chromium.app/Contents/MacOS/Chromium",
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        ];
        for p in &mac_paths {
            let pb = PathBuf::from(p);
            if pb.is_file() {
                return Ok(pb);
            }
        }
    }

    // 3. Windows: check common install directories
    #[cfg(target_os = "windows")]
    {
        let locals = [
            std::env::var("LOCALAPPDATA"),
            std::env::var("ProgramFiles"),
            std::env::var("ProgramFiles(x86)"),
        ];
        for local_var in locals.iter().flatten() {
            let candidates = [
                PathBuf::from(local_var).join("Chromium\\Application\\chrome.exe"),
                PathBuf::from(local_var).join("Google\\Chrome\\Application\\chrome.exe"),
            ];
            for p in &candidates {
                if p.is_file() {
                    tracing::debug!(path = %p.display(), "Found Chromium via install path");
                    return Ok(p.clone());
                }
            }
        }
    }

    Err(LaunchError::ChromiumNotFound)
}

// ── Error type ───────────────────────────────────────────────────────

#[derive(Debug, thiserror::Error)]
pub enum LaunchError {
    #[error("chromium executable not found on PATH or common install locations")]
    ChromiumNotFound,

    #[error("failed to allocate ephemeral port: {0}")]
    PortAllocation(#[from] std::io::Error),

    #[error("failed to spawn {exe}: {source}")]
    SpawnFailed {
        exe: PathBuf,
        #[source]
        source: std::io::Error,
    },

    #[error("webSocketDebuggerUrl not found in /json/version response")]
    DebugUrlNotFound,

    #[error("HTTP request to {url} failed: {source}")]
    HttpConnectionFailed {
        url: String,
        #[source]
        source: reqwest::Error,
    },

    #[error("HTTP response parse error: {0}")]
    HttpParse(#[from] reqwest::Error),
}

//! Typed CDP command builders and response parsers.
//!
//! Each CDP domain (Page, DOM, Runtime, Input) gets a typed command
//! builder function that produces the JSON-RPC wire format and parser
//! functions that extract typed results from responses.

use serde_json::Value as Json;
use std::sync::atomic::AtomicI64;

// ── Wire types ───────────────────────────────────────────────────────

static NEXT_ID: AtomicI64 = AtomicI64::new(1);

fn next_id() -> i64 {
    NEXT_ID.fetch_add(1, std::sync::atomic::Ordering::SeqCst)
}

/// A CDP command ready for serialization to JSON-RPC.
#[derive(Debug, Clone)]
pub struct CdpCommand {
    pub id: i64,
    pub method: String,
    pub params: Json,
}

impl CdpCommand {
    /// Create a new command with an auto-incremented id.
    pub fn new(method: impl Into<String>, params: Json) -> Self {
        Self {
            id: next_id(),
            method: method.into(),
            params,
        }
    }

    /// Serialize to the JSON-RPC wire format.
    #[must_use] 
    pub fn to_json(&self) -> String {
        serde_json::to_string(&serde_json::json!({
            "id": self.id,
            "method": self.method,
            "params": self.params,
        }))
        .unwrap_or_default()
    }
}

/// A parsed CDP response.
#[derive(Debug, Clone)]
pub struct CdpResponse {
    pub id: i64,
    pub result: Option<Json>,
    pub error: Option<CdpError>,
}

impl CdpResponse {
    /// Extract `result` or return the CDP error.
    pub fn into_result(self) -> Result<Json, CdpError> {
        match self.result {
            Some(r) => Ok(r),
            None => Err(self.error.unwrap_or_else(|| CdpError {
                code: -1,
                message: "empty response".into(),
            })),
        }
    }
}

#[derive(Debug, Clone)]
pub struct CdpError {
    pub code: i64,
    pub message: String,
}

impl std::fmt::Display for CdpError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "CDP error {}: {}", self.code, self.message)
    }
}

impl std::error::Error for CdpError {}

/// A CDP event (server push, no id field).
#[derive(Debug, Clone)]
pub struct CdpEvent {
    pub method: String,
    pub params: Json,
}

/// Inbound CDP message.
#[derive(Debug, Clone)]
pub enum CdpMessage {
    Response(CdpResponse),
    Event(CdpEvent),
}

/// Parse a raw JSON-RPC message from the WebSocket into a [`CdpMessage`].
#[must_use] 
pub fn parse_message(text: &str) -> Option<CdpMessage> {
    let val: Json = serde_json::from_str(text).ok()?;
    let obj = val.as_object()?;

    if let Some(id) = obj.get("id").and_then(serde_json::Value::as_i64) {
        let result = obj.get("result").cloned();
        let error = obj.get("error").map(|e| CdpError {
            code: e.get("code").and_then(serde_json::Value::as_i64).unwrap_or(-1),
            message: e
                .get("message")
                .and_then(|v| v.as_str())
                .unwrap_or("unknown")
                .to_string(),
        });
        return Some(CdpMessage::Response(CdpResponse { id, result, error }));
    }

    if let Some(method) = obj.get("method").and_then(|v| v.as_str()) {
        let params = obj.get("params").cloned().unwrap_or(Json::Null);
        return Some(CdpMessage::Event(CdpEvent {
            method: method.to_string(),
            params,
        }));
    }

    None
}

// ── Command builders ──────────────────────────────────────────────────

