1	//! Session manager for goal-scoped browser sessions.
2	//!
3	//! Each session wraps a [`CdpBackend`] (Chromium instance) and is
4	//! identified by a UUID. Sessions are organized by goal — not by tab —
5	//! and share the same goal state store.
6	
7	use std::collections::HashMap;
8	use std::sync::Arc;
9	use std::time::Duration;
10	
11	use ans_cdp::CdpBackend;
12	use ans_core::backend::{BrowserBackend, BrowserError, ImageFormat, PageState};
13	use ans_core::distill::{DistillMode, DistilledPage};
14	use ans_core::session::{Action, ActionOutcome, SessionStatus};
15	use tokio::sync::RwLock;
16	use tracing;
17	use uuid::Uuid;
18	
19	/// Handle to an active browser session.
20	pub struct SessionHandle {
21	    pub session_id: Uuid,
22	    pub goal_id: Uuid,
23	    pub backend: CdpBackend,
24	    pub current_url: String,
25	    pub status: SessionStatus,
26	}
27	
28	/// Thread-safe session registry.
29	///
30	/// Cloning shares the underlying `Arc<RwLock<>>` — all references
31	/// see the same sessions.
32	#[derive(Clone)]
33	pub struct SessionManager {
34	    sessions: Arc<RwLock<HashMap<Uuid, SessionHandle>>>,
35	}
36	
37	impl Default for SessionManager {
38	    fn default() -> Self {
39	        Self::new()
40	    }
41	}
42	
43	impl SessionManager {
44	    #[must_use] 
45	    pub fn new() -> Self {
46	        Self {
47	            sessions: Arc::new(RwLock::new(HashMap::new())),
48	        }
49	    }
50	
51	    /// Create a new session by launching a Chromium instance.
52	    /// If `start_url` is provided, navigate to it immediately.
53	    pub async fn create(
54	        &self,
55	        goal_id: Uuid,
56	        start_url: Option<String>,
57	    ) -> Result<Uuid, BrowserError> {
58	        let session_id = Uuid::new_v4();
59	        tracing::info!(%session_id, %goal_id, "Creating session");
60	
61	        let backend = CdpBackend::launch().await?;
62	
63	        if let Some(url) = &start_url {
64	            let _ = backend
65	                .navigate(url, Duration::from_secs(30))
66	                .await
67	                .map(|state| {
68	                    tracing::info!(url = %state.url, "Session started at URL");
69	                });
70	        }
71	
72	        let handle = SessionHandle {
73	            session_id,
74	            goal_id,
75	            backend,
76	            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
77	            status: SessionStatus::Idle,
78	        };
79	
80	        self.sessions.write().await.insert(session_id, handle);
81	
82	        Ok(session_id)
83	    }
84	
85	    /// Close a session and kill its Chromium process.
86	    pub async fn close(&self, session_id: Uuid) -> Result<(), BrowserError> {
87	        tracing::info!(%session_id, "Closing session");
88	        let handle = self.sessions.write().await.remove(&session_id);
89	        if let Some(handle) = handle {
90	            handle.backend.close().await?;
91	        }
92	        Ok(())
93	    }
94	
95	    /// Close all active sessions.
96	    pub async fn close_all(&self) {
97	        let ids: Vec<Uuid> = self.sessions.read().await.keys().copied().collect();
98	        for id in ids {
99	            let _ = self.close(id).await;
100	        }
101	        tracing::info!("All sessions closed");
102	    }
103	
104	    /// Execute an action on a session.
105	    pub async fn execute_action(
106	        &self,
107	        session_id: Uuid,
108	        action: &Action,
109	    ) -> Result<ActionOutcome, BrowserError> {
110	        let sessions = self.sessions.read().await;
111	        let handle = sessions
112	            .get(&session_id)
113	            .ok_or(BrowserError::BrowserClosed)?;
