132	/// Stealth level — how aggressively to evade detection.
133	///
134	/// Levels are ordered: higher = more evasion, more CPU cost.
135	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
136	pub enum StealthLevel {
137	    /// No stealth — use for internal/trusted pages. Zero overhead.
138	    Off = 0,
139	    /// Core evasions only — webdriver, chrome, plugins, languages.
140	    /// Covers ~90% of detection vectors. Minimal overhead.
141	    Standard = 1,
142	    /// Full evasions — adds canvas, audio, WebGL spoofing.
143	    /// Moderate CPU overhead (~5%).
144	    Aggressive = 2,
145	    /// All evasions including experimental patches.
146	    /// May affect page behavior slightly. Highest CPU cost (~10%).
147	    Paranoid = 3,
148	}
