162	    #[must_use]
163	    pub fn de_escalate(self) -> Self {
164	        match self {
165	            Self::Off | Self::Standard => Self::Off,
166	            Self::Aggressive => Self::Standard,
167	            Self::Paranoid => Self::Aggressive,
